import json

with open('baseline-packages.json') as f: base = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg['resolvedVersion']
        result[pname] = pkgs
    return result

b = extract(base)
a = extract(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for pkg in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bv = b.get(proj,{}).get(pkg)
        av = a.get(proj,{}).get(pkg)
        if bv != av:
            print(f'  {proj}: {pkg} {bv} -> {av}')
            changes = True
if not changes:
    print('  (none besides intended alignments)')

print()
print('=== UNCHANGED ===')
for proj in sorted(b.keys()):
    for pkg in sorted(b.get(proj,{}).keys()):
        bv = b[proj][pkg]
        av = a.get(proj,{}).get(pkg)
        if bv == av:
            print(f'  {proj}: {pkg} = {bv}')
